namespace UniversityCourseCatalog.Models;

public class Department
{
    public required string Id { get; init; }
    public required string Name { get; init; }
    public required string Description { get; init; }
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public required string Id { get; init; }
    public required string DepartmentId { get; init; }
    public required string Code { get; init; }
    public required string Title { get; init; }
    public required string Description { get; init; }
    public required int Credits { get; init; }
    public required string Schedule { get; init; }
    public required string Instructor { get; init; }
    public required string InstructorBio { get; init; }
    public bool IsFeatured { get; init; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100)]
    public string Name { get; set; } = "";

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Za-z0-9\-]+$", ErrorMessage = "Student ID must contain only letters, numbers, and hyphens.")]
    [StringLength(20)]
    public string StudentId { get; set; } = "";

    [Required(ErrorMessage = "Please select a course.")]
    public string CourseId { get; set; } = "";
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = "cs", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
        new() { Id = "math", Name = "Mathematics", Description = "Pure and applied mathematics including statistics and analysis." },
        new() { Id = "eng", Name = "English", Description = "Literature, composition, and creative writing." },
        new() { Id = "phys", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
        new() { Id = "hist", Name = "History", Description = "Exploration of world civilizations and historical events." },
    ];

    private readonly List<Course> _courses =
    [
        // Computer Science
        new() { Id = "cs101", DepartmentId = "cs", Code = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures. No prior experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", Instructor = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education. She holds a Ph.D. from MIT and has published extensively on programming pedagogy.", IsFeatured = true },
        new() { Id = "cs201", DepartmentId = "cs", Code = "CS 201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques. Prerequisites: CS 101.", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM", Instructor = "Dr. James Liu", InstructorBio = "Dr. Liu is an expert in algorithm optimization with research published in top-tier conferences. Previously a software architect at a major tech company.", IsFeatured = true },
        new() { Id = "cs310", DepartmentId = "cs", Code = "CS 310", Title = "Database Systems", Description = "Relational database design, SQL, normalization, and transaction management. Includes a hands-on project building a full database application.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", Instructor = "Prof. Maria Santos", InstructorBio = "Prof. Santos spent a decade in industry working on distributed database systems before joining academia. She specializes in database performance tuning." },
        new() { Id = "cs450", DepartmentId = "cs", Code = "CS 450", Title = "Machine Learning", Description = "Introduction to machine learning concepts including supervised and unsupervised learning, neural networks, and model evaluation. Prerequisites: CS 201, MATH 220.", Credits = 4, Schedule = "Tue/Thu 1:00–2:15 PM", Instructor = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education. She holds a Ph.D. from MIT and has published extensively on programming pedagogy.", IsFeatured = true },

        // Mathematics
        new() { Id = "math110", DepartmentId = "math", Code = "MATH 110", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering problems.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", Instructor = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning mathematics educator who has taught calculus for over 20 years. He is known for making abstract concepts accessible and engaging.", IsFeatured = true },
        new() { Id = "math220", DepartmentId = "math", Code = "MATH 220", Title = "Linear Algebra", Description = "Vector spaces, linear transformations, matrices, determinants, and eigenvalues. Essential for advanced courses in CS, physics, and engineering.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", Instructor = "Dr. Elena Volkov", InstructorBio = "Dr. Volkov completed her doctorate at the University of Moscow and specializes in applied linear algebra and numerical methods." },
        new() { Id = "math330", DepartmentId = "math", Code = "MATH 330", Title = "Probability & Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis with real-world applications.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", Instructor = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning mathematics educator who has taught calculus for over 20 years. He is known for making abstract concepts accessible and engaging." },

        // English
        new() { Id = "eng101", DepartmentId = "eng", Code = "ENG 101", Title = "College Composition", Description = "Develop essential writing skills through expository and argumentative essays. Emphasis on clear thesis development, evidence-based reasoning, and revision strategies.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", Instructor = "Prof. David Park", InstructorBio = "Prof. Park is a published author and writing instructor with expertise in rhetoric and composition. He has mentored hundreds of students in developing their writing voice." },
        new() { Id = "eng215", DepartmentId = "eng", Code = "ENG 215", Title = "American Literature", Description = "Survey of major American literary works from the colonial period to the present. Examines themes of identity, freedom, and the American experience.", Credits = 3, Schedule = "Tue/Thu 2:00–3:15 PM", Instructor = "Dr. Angela Brooks", InstructorBio = "Dr. Brooks is an authority on 20th-century American fiction. Her book on the Harlem Renaissance received critical acclaim.", IsFeatured = true },
        new() { Id = "eng320", DepartmentId = "eng", Code = "ENG 320", Title = "Creative Writing Workshop", Description = "Workshop-based course in fiction and poetry writing. Students produce an original portfolio and participate in peer review sessions.", Credits = 3, Schedule = "Wed 6:00–8:30 PM", Instructor = "Prof. David Park", InstructorBio = "Prof. Park is a published author and writing instructor with expertise in rhetoric and composition. He has mentored hundreds of students in developing their writing voice." },

        // Physics
        new() { Id = "phys101", DepartmentId = "phys", Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions. Co-requisite: MATH 110.", Credits = 4, Schedule = "Mon/Wed/Fri 8:00–8:50 AM + Thu Lab 2:00–4:50 PM", Instructor = "Dr. Thomas Nguyen", InstructorBio = "Dr. Nguyen is an experimental physicist who previously worked at CERN. He brings real-world particle physics experience into the classroom." },
        new() { Id = "phys202", DepartmentId = "phys", Code = "PHYS 202", Title = "Electromagnetism", Description = "Electric fields, magnetic fields, Maxwell's equations, and electromagnetic waves. Prerequisites: PHYS 101, MATH 220.", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM + Fri Lab 1:00–3:50 PM", Instructor = "Dr. Priya Patel", InstructorBio = "Dr. Patel's research focuses on condensed matter physics. She received the university's Distinguished Teaching Award in 2024." },

        // History
        new() { Id = "hist101", DepartmentId = "hist", Code = "HIST 101", Title = "World Civilizations I", Description = "Survey of world history from ancient civilizations through the medieval period. Examines political, social, and cultural developments across regions.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:15 PM", Instructor = "Dr. Michael Torres", InstructorBio = "Dr. Torres is a historian specializing in cross-cultural exchange in the ancient world. He has conducted archaeological fieldwork in the Mediterranean." },
        new() { Id = "hist250", DepartmentId = "hist", Code = "HIST 250", Title = "Modern European History", Description = "Europe from the French Revolution to the present. Topics include industrialization, nationalism, world wars, and European integration.", Credits = 3, Schedule = "Mon/Wed 3:30–4:45 PM", Instructor = "Dr. Claire Dubois", InstructorBio = "Dr. Dubois holds a joint appointment with the Political Science department. Her research examines the intersection of politics and culture in modern France.", IsFeatured = true },
    ];

    public IReadOnlyList<Department> GetDepartments() => _departments;

    public Department? GetDepartment(string id) => _departments.Find(d => d.Id == id);

    public IReadOnlyList<Course> GetAllCourses() => _courses;

    public IReadOnlyList<Course> SearchCourses(string? searchTerm, string? departmentId, int? minCredits, int? maxCredits)
    {
        var query = _courses.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(departmentId))
        {
            query = query.Where(c => c.DepartmentId == departmentId);
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Instructor.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        if (minCredits.HasValue)
        {
            query = query.Where(c => c.Credits >= minCredits.Value);
        }

        if (maxCredits.HasValue)
        {
            query = query.Where(c => c.Credits <= maxCredits.Value);
        }

        return query.OrderBy(c => c.Code).ToList();
    }

    public IReadOnlyList<Course> GetFeaturedCourses() =>
        _courses.Where(c => c.IsFeatured).ToList();

    public IReadOnlyList<Course> GetCoursesByDepartment(string departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).OrderBy(c => c.Code).ToList();

    public Course? GetCourse(string id) => _courses.Find(c => c.Id == id);
}

