@page "/courses"
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

<form method="get" class="row g-3 mb-4">
    <div class="col-md-4">
        <label for="search" class="form-label">Search</label>
        <input type="text" class="form-control" id="search" name="search" value="@Search" placeholder="Title, code, or instructor..." />
    </div>
    <div class="col-md-3">
        <label for="department" class="form-label">Department</label>
        <select class="form-select" id="department" name="department">
            <option value="">All Departments</option>
            @foreach (var dept in Catalog.GetDepartments())
            {
                <option value="@dept.Id" selected="@(Department == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <label for="minCredits" class="form-label">Min Credits</label>
        <input type="number" class="form-control" id="minCredits" name="minCredits" value="@MinCredits" min="1" max="6" />
    </div>
    <div class="col-md-2">
        <label for="maxCredits" class="form-label">Max Credits</label>
        <input type="number" class="form-control" id="maxCredits" name="maxCredits" value="@MaxCredits" min="1" max="6" />
    </div>
    <div class="col-md-1 d-flex align-items-end">
        <button type="submit" class="btn btn-primary">Filter</button>
    </div>
</form>

@{
    var courses = Catalog.SearchCourses(Search, Department, MinCredits, MaxCredits);
}

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}
else
{
    <p class="text-muted mb-3">Showing @courses.Count course(s)</p>

    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Department</th>
                    <th>Credits</th>
                    <th>Instructor</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in courses)
                {
                    var dept = Catalog.GetDepartment(course.DepartmentId);
                    <tr>
                        <td>@course.Code</td>
                        <td>@course.Title</td>
                        <td>@dept?.Name</td>
                        <td>@course.Credits</td>
                        <td>@course.Instructor</td>
                        <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public string? Department { get; set; }
    [SupplyParameterFromQuery] public int? MinCredits { get; set; }
    [SupplyParameterFromQuery] public int? MaxCredits { get; set; }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p class="text-muted">Submit a request to enroll in a course. All fields are required.</p>

@if (_submitted)
{
    <div class="alert alert-success" role="alert">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Thank you, <strong>@_model.Name</strong>. Your enrollment request for
            <strong>@(Catalog.GetCourse(_model.CourseId)?.Title ?? _model.CourseId)</strong>
            has been received.</p>
        <hr />
        <p class="mb-0">Student ID: @_model.StudentId — You will receive a confirmation via your university email.</p>
    </div>
    <a href="/enroll" class="btn btn-primary">Submit Another Request</a>
}
else
{
    <div class="row">
        <div class="col-md-6">
            <EditForm method="post" Model="_model" OnValidSubmit="HandleSubmit" FormName="enrollment">
                <DataAnnotationsValidator />
                <AntiforgeryToken />

                <div class="mb-3">
                    <label for="name" class="form-label">Full Name</label>
                    <InputText id="name" class="form-control" @bind-Value="_model.Name" />
                    <ValidationMessage For="() => _model.Name" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" class="form-control" @bind-Value="_model.StudentId" placeholder="e.g. STU-12345" />
                    <ValidationMessage For="() => _model.StudentId" />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <InputSelect id="courseId" class="form-select" @bind-Value="_model.CourseId">
                        <option value="">— Select a course —</option>
                        @foreach (var course in Catalog.GetAllCourses().OrderBy(c => c.Code))
                        {
                            <option value="@course.Id">@course.Code – @course.Title</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => _model.CourseId" />
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
            </EditForm>
        </div>
    </div>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest _model { get; set; } = new();

    [SupplyParameterFromQuery]
    public string? CourseId { get; set; }

    private bool _submitted;

    protected override void OnInitialized()
    {
        if (!string.IsNullOrEmpty(CourseId) && string.IsNullOrEmpty(_model.CourseId))
        {
            _model.CourseId = CourseId;
        }
    }

    private void HandleSubmit()
    {
        _submitted = true;
    }
}

